def post_attr_hash(post_attr)
      @post_attr_hash[post_attr] ||= begin
        hash = Hash.new { |h, key| h[key] = [] }
        posts.docs.each do |p|
          p.data[post_attr]&.each { |t| hash[t] << p }
        end
        hash.each_value { |posts| posts.sort!.reverse! }
        hash
      end
    end

def categories_from_path(special_dir)
      if relative_path.start_with?(special_dir)
        superdirs = []
      else
        superdirs = relative_path.sub(Document.superdirs_regex(special_dir), "")
        superdirs = superdirs.split(File::SEPARATOR)
        superdirs.reject! { |c| c.empty? || c == special_dir || c == basename }
      end

      merge_data!({ "categories" => superdirs }, :source => "file path")
    end

def fetch(record_ids)
        records = @model_class.where(@find_by => record_ids)
        record_lookup = {}
        if @find_by_many
          records.each do |r|
            key = @find_by.map { |fb| r.public_send(fb) }
            record_lookup[key] = r
          end
        else
          records.each { |r| record_lookup[r.public_send(@find_by)] = r }
        end
        record_ids.map { |id| record_lookup[id] }
      end

def initialize(proxy = nil, dns = nil, headers = {})
