def pg_class_relname(type, opts)
        ds = metadata_dataset.from(:pg_class).where(:relkind=>type).select(:relname).server(opts[:server]).join(:pg_namespace, :oid=>:relnamespace)
        ds = filter_schema(ds, opts)
        m = output_identifier_meth
        if defined?(yield)
          yield(ds)
        elsif opts[:qualify]
          ds.select_append{pg_namespace[:nspname]}.map{|r| Sequel.qualify(m.call(r[:nspname]).to_s, m.call(r[:relname]).to_s)}
        else
          ds.map{|r| m.call(r[:relname])}
        end
      end

def insert_returning_columns(ds)
          return unless ds.supports_returning?(:insert)
          return unless values = ds.opts[:select]

          # SELECT table.* -> RETURNING *
          if values.length == 1 && values[0].is_a?(Sequel::SQL::ColumnAll)
            return RETURN_ALL
          end

          # SELECT column1, table.column2, ... -> RETURNING column1, column2, ...
          values = values.map{|v| ds.unqualified_column_for(v)}
          if values.all?
            values
          end
        end

def reload_config
        @runtime = nil
        options, _paths = ::RuboCop::Options.new.parse([])

        config_store = ::RuboCop::ConfigStore.new
        config_store.apply_options!(options)
        @runtime = ::RuboCop::LSP::Runtime.new(config_store)
      rescue ::RuboCop::Error => e
        @message_queue << Notification.window_show_message(
          "RuboCop configuration error: #{e.message}. Formatting will not be available.",
          type: Constant::MessageType::ERROR
        )
      end

